const formatData = $('Format for Update').item.json;
const executionStart = new Date(formatData.timestamp);
const executionEnd = new Date();
const duration = (executionEnd - executionStart) / 1000;

return [{
  json: {
    timestamp: new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }),
    collectionId: formatData.collectionId,
    itemsUpdated: formatData.count,
    itemsPublished: formatData.count,
    executionDuration: `${duration}s`,
    postNames: formatData.items.map(i => i.fieldData.name).join('\n'),
    itemIds: formatData.itemIds.join('\n')
  }
}];

