const data = $input.first().json;
const output = data.output || data;
const itemsToUpdate = output.filter(i => i.needsUpdate);

if (itemsToUpdate.length === 0) {
  return [];
}

const formattedItems = itemsToUpdate.map(item => {
  const fieldData = {};
  if (item.updates.name !== null) fieldData.name = item.updates.name;
  if (item.updates['project-summary'] !== null) fieldData['project-summary'] = item.updates['project-summary'];

  return {
    id: item.id,
    fieldData: fieldData
  };
});

return [{
  json: {
    // Make sure to update the correct collection ID ⚠️
    collectionId: "xxxxxxxxxx",
    items: formattedItems,
    itemIds: formattedItems.map(i => i.id),
    count: itemsToUpdate.length,
    timestamp: new Date().toISOString()
  }
}];
